class Solution {
  public:
    int minimumDepth(Node* root) {
        if(root == NULL) 
          return 0;
        if(root->left == NULL) 
          return 1 + minimumDepth(root->right);
        if(root->right == NULL) 
          return 1 + minimumDepth(root->left);
        return 1 + min(minimumDepth(root->left), 
               minimumDepth(root->right));
    }

};

